import React, { useContext } from 'react';

import { UserContext } from '@providers/User';
import CostSplitDetails from '@components/CostSplitDetails';
import PrintableInvoice from '@components/Printables/Invoice';

/**
 * React component to display Bill details for payment transaction order.
 * This shall be shown in a bottom-sheet when user clicks on any payment transaction order to view bill
 * @param {Object} prop - prop object passed to this component
 * @param {Number|String} prop.billId - Bill number
 * @param {Number} prop.amount - Bill amount
 * @param {Number|Date} prop.billPayTimestamp - Bill pay timestamp. Unix epoch or Date
 */
export default function Bill({ billId, amount, billPayTimestamp }) {
	const { id, name, email, phone } = useContext(UserContext);
	return (
		<>
			<CostSplitDetails amt={amount} amtIncludesTaxNFees={true} />
			<PrintableInvoice invoiceId={billId} invoiceAmt={amount} paymentTimestamp={billPayTimestamp} userId={id} name={name} email={email} phone={phone} />
		</>
	);
}
