import React from 'react';
import FullWidthRestrictedPageLayout from '@layouts/FullWidthRestrictedPage';
import BrowserOnly from '@components/BrowserOnly';
import { Seo_noIndex } from '@components/Seo';

export default function PaymentTransactionsPage() {
	return (
		<FullWidthRestrictedPageLayout>
			<h1>
				Payment <span>Transactions</span>
			</h1>
			<BrowserOnly>
				{() => {
					const PaymentTransactions = require('@components/PaymentTransactions').default; //eslint-disable-line no-undef
					return <PaymentTransactions />;
				}}
			</BrowserOnly>
		</FullWidthRestrictedPageLayout>
	);
}

export function Head() {
	return <Seo_noIndex title="Payment transactions" description="List of your purchase payment transactions and invoices" />;
}
