import React, { useContext, useEffect, useState } from 'react';

import LoginHero from '@components/LoginHero';
import Loading from '@components/ui/Loading';

import { UserContext } from '@providers/User';

/** Displays Login hero if user isn't logged in. Imported in page layout */
export default function LoginGateway({ children }) {
	const [isLoadingDone, setIsLoadingDone] = useState(false);
	const { id } = useContext(UserContext);

	useEffect(() => {
		//in order to prevent flickering when 'id' is being read from the context
		//since the inital state of 'id' is 'null' and then when the actual value comes in (it causes a flickering effect)
		//this flickering effect may only be visible in dev mode but need to check
		setTimeout(() => {
			setIsLoadingDone(true);
		}, 100);
	}, []);

	if (!isLoadingDone) return <Loading coverFullPage={true} />;
	return id ? <main>{children}</main> : <LoginHero />;
}
